import * as React from 'react';
import { Container, Typography, Box, Button, Paper, Grid, Avatar, Stack } from '@mui/material';
import { Link } from 'react-router-dom';
import ForumIcon from '@mui/icons-material/Forum';
import QuestionAnswerIcon from '@mui/icons-material/QuestionAnswer';
import EmojiEventsIcon from '@mui/icons-material/EmojiEvents';

export default function Home() {
  // Lấy user từ localStorage để xác định trạng thái đăng nhập
  const user = React.useMemo(() => {
    try {
      return JSON.parse(localStorage.getItem('user'));
    } catch {
      return null;
    }
  }, []);

  return (
    <Container maxWidth="md" sx={{mt:6}}>
      <Paper elevation={4} sx={{p:5, textAlign: 'center', background: 'linear-gradient(135deg, #e3f2fd 0%, #fff 100%)'}}>
        <Stack direction="row" spacing={2} justifyContent="center" alignItems="center" sx={{mb:2}}>
          <Avatar sx={{ bgcolor: 'primary.main', width: 56, height: 56 }}>
            <ForumIcon fontSize="large" />
          </Avatar>
          <Typography variant="h3" fontWeight={700} color="primary.main">
            Diễn đàn SV
          </Typography>
        </Stack>
        <Typography variant="h6" color="text.secondary" gutterBottom>
          Nơi sinh viên hỏi đáp, chia sẻ kiến thức và kết nối cộng đồng!
        </Typography>
        <Grid container spacing={3} sx={{mt:4, mb:4}}>
          <Grid item xs={12} md={4}>
            <Paper elevation={2} sx={{p:3, minHeight:140, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center'}}>
              <QuestionAnswerIcon color="primary" sx={{fontSize:40, mb:1}} />
              <Typography variant="subtitle1" fontWeight={600}>Hỏi đáp mọi chủ đề</Typography>
              <Typography variant="body2" color="text.secondary">Đặt câu hỏi, nhận câu trả lời nhanh chóng từ cộng đồng sinh viên.</Typography>
            </Paper>
          </Grid>
          <Grid item xs={12} md={4}>
            <Paper elevation={2} sx={{p:3, minHeight:140, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center'}}>
              <EmojiEventsIcon color="warning" sx={{fontSize:40, mb:1}} />
              <Typography variant="subtitle1" fontWeight={600}>Tích điểm & vinh danh</Typography>
              <Typography variant="body2" color="text.secondary">Tham gia trả lời, tích điểm, nhận huy hiệu và được vinh danh trên bảng xếp hạng.</Typography>
            </Paper>
          </Grid>
          <Grid item xs={12} md={4}>
            <Paper elevation={2} sx={{p:3, minHeight:140, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center'}}>
              <ForumIcon color="success" sx={{fontSize:40, mb:1}} />
              <Typography variant="subtitle1" fontWeight={600}>Kết nối bạn bè</Typography>
              <Typography variant="body2" color="text.secondary">Tìm kiếm, kết nối và học hỏi cùng các sinh viên khác trên toàn quốc.</Typography>
            </Paper>
          </Grid>
        </Grid>
        <Box sx={{mt:2, display:'flex', justifyContent:'center', gap:2}}>
          <Button variant="contained" color="primary" component={Link} to="/questions" size="large">Khám phá câu hỏi</Button>
          {!user && <Button variant="outlined" color="primary" component={Link} to="/login" size="large">Đăng nhập</Button>}
          {!user && <Button variant="outlined" color="secondary" component={Link} to="/register" size="large">Đăng ký</Button>}
          {user && <Button variant="contained" color="success" component={Link} to="/questions/new" size="large">Đặt câu hỏi mới</Button>}
        </Box>
      </Paper>
    </Container>
  );
}
